class TestOwnOrganisationAccess:
    """A privacy-officer SHALL be able to read audit logs of their own org."""

    def test_get_logs_returns_list_for_own_org(
        self, service, privacy_officer_org_a
    ):
        logs = service.get_logs_for_organisation(privacy_officer_org_a, ORG_A)

        assert isinstance(logs, list)

    def test_get_logs_returns_correct_entries_for_own_org(
        self, service, privacy_officer_org_a
    ):
        logs = service.get_logs_for_organisation(privacy_officer_org_a, ORG_A)

        assert len(logs) == 2
        assert all(log.organisation_id == ORG_A for log in logs)

    def test_get_logs_for_org_with_no_entries_returns_empty_list(
        self, service, privacy_officer_org_c
    ):
        logs = service.get_logs_for_organisation(privacy_officer_org_c, ORG_C)

        assert logs == []

    def test_get_log_by_id_returns_entry_for_own_org(
        self, service, privacy_officer_org_a
    ):
        entry = service.get_log_by_id(privacy_officer_org_a, "log-001")

        assert entry.log_id == "log-001"
        assert entry.organisation_id == ORG_A

    def test_get_log_by_id_returns_correct_message(
        self, service, privacy_officer_org_a
    ):
        entry = service.get_log_by_id(privacy_officer_org_a, "log-001")

        assert entry.message == "Login event – org A"

    def test_privacy_officer_org_b_can_access_own_logs(
        self, service, privacy_officer_org_b
    ):
        logs = service.get_logs_for_organisation(privacy_officer_org_b, ORG_B)

        assert len(logs) == 1
        assert logs[0].organisation_id == ORG_B

    def test_repository_queried_with_correct_organisation_id(
        self, service, log_repository, privacy_officer_org_a
    ):
        service.get_logs_for_organisation(privacy_officer_org_a, ORG_A)

        log_repository.find_by_organisation.assert_called_once_with(ORG_A)


