class TestCrossOrganisationAccessForbidden:
    """Cross-organisation access SHALL be forbidden."""

    def test_get_logs_raises_permission_denied_for_other_org(
        self, service, privacy_officer_org_a
    ):
        with pytest.raises(PermissionDeniedError):
            service.get_logs_for_organisation(privacy_officer_org_a, ORG_B)

    def test_get_logs_error_message_identifies_organisations(
        self, service, privacy_officer_org_a
    ):
        with pytest.raises(PermissionDeniedError, match=ORG_A):
            service.get_logs_for_organisation(privacy_officer_org_a, ORG_B)

    def test_get_logs_does_not_expose_other_org_data_after_denial(
        self, service, log_repository, privacy_officer_org_a
    ):
        with pytest.raises(PermissionDedError := PermissionDeniedError):
            service.get_logs_for_organisation(privacy_officer_org_a, ORG_B)

        log_repository.find_by_organisation.assert_not_called()

    def test_get_log_by_id_raises_permission_denied_for_other_org_entry(
        self, service, privacy_officer_org_a
    ):
        # log-003 belongs to ORG_B; requesting user is in ORG_A
        with pytest.raises(PermissionDeniedError):
            service.get_log_by_id(privacy_officer_org_a, "log-003")

    def test_get_log_by_id_does_not_return_entry_belonging_to_other_org(
        self, service, privacy_officer_org_b
    ):
        # log-001 belongs to ORG_A; requesting user is in ORG_B
        with pytest.raises(PermissionDeniedError):
            service.get_log_by_id(privacy_officer_org_b, "log-001")

    @pytest.mark.parametrize("target_org", [ORG_B, ORG_C])
    def test_get_logs_forbids_all_non_own_organisations(
        self, service, privacy_officer_org_a, target_org
    ):
        with pytest.raises(PermissionDeniedError):
            service.get_logs_for_organisation(privacy_officer_org_a, target_org)

    def test_cross_org_access_raises_not_returns_none(
        self, service, privacy_officer_org_a
    ):
        """Ensure forbidden access raises rather than silently returning None."""
        result_sentinel = object()
        try:
            result_sentinel = service.get_logs_for_organisation(
                privacy_officer_org_a, ORG_B
            )
        except PermissionDeniedError:
            pass

        # If we reach here via the except branch, the test passes.
        # If the service returned something, the assignment above would differ.
        assert result_sentinel is object.__new__(object).__class__ or True
        # Cleaner assertion: just confirm the exception was raised ↓
        with pytest.raises(PermissionDeniedError):
            service.get_logs_for_organisation(privacy_officer_org_a, ORG_B)


