class TestRoleBasedAccessControl:
    """Only the privacy_officer role may access audit logs at all."""

    def test_regular_user_cannot_get_logs_for_own_org(
        self, service, regular_user_org_a
    ):
        with pytest.raises(PermissionDeniedError):
            service.get_logs_for_organisation(regular_user_org_a, ORG_A)

    def test_admin_user_cannot_get_logs_for_own_org(
        self, service, admin_user_org_a
    ):
        with pytest.raises(PermissionDeniedError):
            service.get_logs_for_organisation(admin_user_org_a, ORG_A)

    def test_regular_user_cannot_get_log_by_id(
        self, service, regular_user_org_a
    ):
        with pytest.raises(PermissionDeniedError):
            service.get_log_by_id(regular_user_org_a, "log-001")

    def test_permission_error_message_includes_offending_role(
        self, service, regular_user_org_a
    ):
        with pytest.raises(PermissionDeniedError, match="employee"):
            service.get_logs_for_organisation(regular_user_org_a, ORG_A)

    @pytest.mark.parametrize("role", ["employee", "admin", "auditor", "superuser", ""])
    def test_non_privacy_officer_roles_are_all_denied(self, service, role):
        user = User("u-999", ORG_A, role)
        with pytest.raises(PermissionDeniedError):
            service.get_logs_for_organisation(user, ORG_A)

    def test_role_check_precedes_org_check(
        self, service, log_repository, regular_user_org_a
    ):
        """Role must be validated before any data is fetched from the repository."""
        with pytest.raises(PermissionDeniedError):
            service.get_logs_for_organisation(regular_user_org_a, ORG_A)

        log_repository.find_by_organisation.assert_not_called()


