# Tests – edge cases and robustness
# ---------------------------------------------------------------------------

class TestEdgeCases:

    def test_get_log_by_id_raises_not_found_for_nonexistent_log(
        self, service, privacy_officer_org_a
    ):
        with pytest.raises(NotFoundError):
            service.get_log_by_id(privacy_officer_org_a, "log-nonexistent")

    def test_not_found_does_not_leak_other_org_existence(
        self, service, privacy_officer_org_a
    ):
        """
        A missing log should raise NotFoundError, not PermissionDeniedError,
        to avoid leaking whether a log exists in another organisation.
        (Adjust this test if your security policy prefers the opposite behaviour.)
        """
        with pytest.raises(NotFoundError):
            service.get_log_by_id(privacy_officer_org_a, "log-nonexistent")

    def test_empty_organisation_id_is_denied(self, service):
        user = User("u-001", ORG_A, "privacy_officer")
        with pytest.raises((PermissionDeniedError, ValueError)):
            service.get_logs_for_organisation(user, "")

    def test_none_organisation_id_is_denied(self, service):
        user = User("u-001", ORG_A, "privacy_officer")
        with pytest.raises((PermissionDeniedError, TypeError, ValueError)):
            service.get_logs_for_organisation(user, None)

    def test_repository_is_not_called_on_cross_org_request(
        self, service, log_repository, privacy_officer_org_a
    ):
        with pytest.raises(PermissionDeniedError):
            service.get_logs_for_organisation(privacy_officer_org_a, ORG_B)

        log_repository.find_by_organisation.assert_not_called()

    def test_multiple_officers_from_same_org_each_see_same_logs(
        self, service
    ):
        officer_1 = User("po-A1", ORG_A, "privacy_officer")
        officer_2 = User("po-A2", ORG_A, "privacy_officer")

        logs_1 = service.get_logs_for_organisation(officer_1, ORG_A)
        logs_2 = service.get_logs_for_organisation(officer_2, ORG_A)

        assert [l.log_id for l in logs_1] == [l.log_id for l in logs_2]

    def test_officer_from_org_a_and_officer_from_org_b_see_different_logs(
        self, service, privacy_officer_org_a, privacy_officer_org_b
    ):
        logs_a = service.get_logs_for_organisation(privacy_officer_org_a, ORG_A)
        logs_b = service.get_logs_for_organisation(privacy_officer_org_b, ORG_B)

        org_ids_a = {log.organisation_id for log in logs_a}
        org_ids_b = {log.organisation_id for log in logs_b}

        assert org_ids_a.isdisjoint(org_ids_b), (
            "Logs from different organisations must not overlap."
        )
